User { id: uuid email: string plan: free | single | annual planExpiry: timestamp | null // annual 过期时间 syncQuota: number // 剩余免费同步次数（free 用户为 1） createdAt: timestamp }
Draft { id: uuid userId: uuid applicationId: string | null // DS-160 Application ID status: draft | syncing | synced | submitted visaType: B | F | J | H | ... label: string // 用户自定义备注，如"王伟 2026续签" formData: FormData // AES-256-GCM 加密存储 createdAt: timestamp updatedAt: timestamp }
Order { id: uuid userId: uuid type: single | annual amount: number // 单位：分 status: pending | paid | refunded paidAt: timestamp | null }
